class PWAInstall{constructor(){this.deferredPrompt=null;this.installButton=null;}init(){this.setupInstallListener();}setupInstallListener(){window.addEventListener('beforeinstallprompt',(e)=>{this.deferredPrompt=e;this.showInstallButton();});window.addEventListener('appinstalled',()=>{this.deferredPrompt=null;this.hideInstallButton();});}showInstallButton(){this.installButton=document.getElementById('install-button');if(this.installButton){this.installButton.style.display='block';this.installButton.addEventListener('click',()=>this.promptInstall());}}hideInstallButton(){if(this.installButton){this.installButton.style.display='none';}}async promptInstall(){if(!this.deferredPrompt){return;}this.deferredPrompt.prompt();const{outcome}=await this.deferredPrompt.userChoice;this.deferredPrompt=null;this.hideInstallButton();}async canInstall(){return!!this.deferredPrompt;}}const pwaInstall=new PWAInstall();if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',()=>pwaInstall.init());}else{pwaInstall.init();}export{PWAInstall,pwaInstall};export default pwaInstall;